head.b:skin:
:root {
  --navy: #0f2a4a;
  --red: #c1121f;
  --white: #ffffff;
  --bg: #f4f7fb;
  --text: #1f2937;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Cairo', Arial, sans-serif;
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
}

a {
  text-decoration: none;
  color: inherit;
}

.container {
  width: min(1120px, 92%);
  margin: 0 auto;
}

.site-header {
  background: var(--white);
  box-shadow: 0 2px 14px rgba(0, 0, 0, 0.08);
}

.header-inner {
  min-height: 94px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 10px 0;
}

#header {
  width: 100%;
}

#header .widget,
#header .widget-content {
  text-align: center;
}

#header img {
  max-width: 280px;
  width: auto;
  height: auto;
}

#header h1,
#header h2,
#header .title {
  margin: 0;
  color: var(--navy);
  font-size: 1.5rem;
  font-weight: 800;
}

.hero {
  background: linear-gradient(120deg, #0b1f37 0%, #12335a 100%);
  color: var(--white);
  text-align: center;
  padding: 84px 0 92px;
}

.hero h1 {
  margin: 0;
  font-size: clamp(1.75rem, 3.1vw, 2.6rem);
  font-weight: 800;
}

.hero p {
  margin: 15px auto 0;
  max-width: 780px;
  opacity: 0.95;
  font-size: 1.02rem;
}

.search-wrap {
  margin-top: -46px;
}

.search-card {
  background: var(--white);
  border-radius: 14px;
  box-shadow: 0 12px 32px rgba(15, 42, 74, 0.16);
  padding: 24px;
}

.search-form {
  display: flex;
  gap: 12px;
}

.search-form input[name='q'] {
  flex: 1;
  min-height: 56px;
  border: 1px solid #d7dee7;
  border-radius: 10px;
  padding: 0 16px;
  font-size: 1rem;
  font-family: inherit;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.search-form input[name='q']:focus {
  border-color: var(--navy);
  box-shadow: 0 0 0 3px rgba(15, 42, 74, 0.14);
}

.search-form button {
  min-height: 56px;
  border: 0;
  border-radius: 10px;
  padding: 0 24px;
  font-family: inherit;
  font-size: 1rem;
  font-weight: 700;
  color: var(--white);
  background: var(--red);
  cursor: pointer;
}

.content-section {
  padding: 42px 0 74px;
}

.empty-state,
.result-card {
  background: var(--white);
  border-radius: 14px;
  box-shadow: 0 10px 26px rgba(0, 0, 0, 0.07);
  padding: 24px;
}

.result-card + .result-card {
  margin-top: 18px;
}

.result-title {
  margin: 0 0 14px;
  text-align: center;
  color: var(--navy);
  font-size: 1.4rem;
  font-weight: 800;
  word-break: break-word;
}

.result-body {
  text-align: center;
}

.result-body img {
  max-width: 100%;
  height: auto;
  border-radius: 10px;
  border: 1px solid #d9dee6;
}

.not-found {
  margin: 0;
  text-align: center;
  color: var(--red);
  font-size: 1.05rem;
  font-weight: 700;
}

.hint {
  margin: 0;
  text-align: center;
  color: #64748b;
}

.site-footer {
  background: #0d1422;
  color: #d7dde7;
  padding: 18px 0;
}

.footer-inner {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  align-items: center;
  gap: 14px;
}

.footer-center {
  text-align: center;
}

.footer-right {
  text-align: right;
}

.social-links {
  display: inline-flex;
  gap: 12px;
}

.social-links a {
  color: #fff;
}

@media (max-width: 768px) {
  .search-form {
    flex-direction: column;
  }

  .footer-inner {
    grid-template-columns: 1fr;
    text-align: center;
  }

  .footer-center,
  .footer-right {
    text-align: center;
  }
}
